import anthropic
import json

client = anthropic.Anthropic()
MODEL = "claude-sonnet-4-6"


def retrieve_and_map(target_problem: str, domain_hints: list[str] | None = None) -> dict:
    """
    Stage 1: Find a structurally analogous source domain and map elements.
    Returns {source_domain, elements: [{source, target, role}], relationships: [str]}
    """
    hint_text = ""
    if domain_hints:
        hint_text = f"\n\nConsider these potential source domains: {', '.join(domain_hints)}"

    prompt = f"""You are performing analogical reasoning.

Target problem: {target_problem}{hint_text}

Step 1 — Identify a source domain that is STRUCTURALLY similar to this problem
(similar relationships between parts, not similar surface features).

Step 2 — Map each target element to its corresponding source element.

Step 3 — List the key relationships that hold in the source domain.

Respond with JSON only:
{{
  "source_domain": "name of the source domain",
  "source_description": "one sentence explaining the source domain",
  "element_mappings": [
    {{"target_element": "...", "source_element": "...", "shared_role": "..."}}
  ],
  "source_relationships": [
    "relationship that holds in the source domain"
  ]
}}"""

    response = client.messages.create(
        model=MODEL,
        max_tokens=768,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = response.content[0].text.strip().lstrip("```json").lstrip("```").rstrip("```").strip()
    return json.loads(raw)


def transfer_and_infer(target_problem: str, mapping: dict) -> dict:
    """
    Stage 2: Transfer source relationships to the target domain and generate inferences.
    Returns {transferred_principles: [str], novel_inferences: [str], solution_sketch: str}
    """
    mapping_text = json.dumps(mapping, indent=2)
    prompt = f"""You are completing an analogical reasoning chain.

Target problem: {target_problem}

Analogy established in Stage 1:
{mapping_text}

Now:
1. Transfer each source relationship to the target domain using the element mappings.
2. Generate novel inferences about the target problem that were not obvious before
   the analogy (things the source domain "teaches" us about the target).
3. Sketch a solution approach for the target problem based on this analogy.

Respond with JSON only:
{{
  "transferred_principles": [
    "principle transferred from source to target"
  ],
  "novel_inferences": [
    "non-obvious insight the analogy reveals about the target"
  ],
  "solution_sketch": "a paragraph describing how to approach the target problem, informed by the analogy"
}}"""

    response = client.messages.create(
        model=MODEL,
        max_tokens=768,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = response.content[0].text.strip().lstrip("```json").lstrip("```").rstrip("```").strip()
    return json.loads(raw)


def analogical_reasoning(problem: str, domain_hints: list[str] | None = None) -> dict:
    """Full two-stage analogical reasoning pipeline."""
    mapping = retrieve_and_map(problem, domain_hints)
    inferences = transfer_and_infer(problem, mapping)
    return {"mapping": mapping, "inferences": inferences}

def analogical_few_shot(problem: str, examples: list[dict]) -> str:
    """
    Apply analogical reasoning via few-shot prompting.
    Each example: {"problem": str, "solution": str}
    """
    example_block = "\n\n".join(
        f"Problem: {ex['problem']}\nSolution: {ex['solution']}"
        for ex in examples
    )
    prompt = f"""{example_block}

Problem: {problem}
Solution:"""

    response = client.messages.create(
        model=MODEL,
        max_tokens=512,
        messages=[{"role": "user", "content": prompt}],
    )
    return response.content[0].text.strip()


# Example: solving a new rate-limit problem using structural analogy to token buckets
examples = [
    {
        "problem": "A coffee shop can serve 10 customers per minute. During morning rush, 30 arrive per minute. How should it manage the queue?",
        "solution": "Use a token bucket: generate 10 tokens/min (service capacity). Each arriving customer consumes a token. If no tokens remain, the customer waits or is turned away. Burst capacity = bucket size (e.g. 20 tokens allows a short burst of 20 back-to-back customers).",
    },
    {
        "problem": "A printer can handle 5 print jobs per minute. Jobs arrive unevenly. How should it prioritize?",
        "solution": "Use a weighted token bucket per job class: high-priority jobs get 3 tokens/min, normal get 2. Each job consumes one token from its class bucket. This bounds throughput per class while allowing burst absorption up to the bucket size.",
    },
]

new_problem = (
    "An API gateway serves 3 tenants. Tenant A sends 100 req/s on average, "
    "B sends 50 req/s, and C sends 10 req/s. The gateway capacity is 120 req/s. "
    "How should it allocate capacity fairly?"
)

solution = analogical_few_shot(new_problem, examples)
print(solution)

def validate_inference(inference: str, target_problem: str) -> dict:
    """
    Ask the LLM to stress-test an analogical inference against target-domain constraints.
    Returns {valid: bool, caveat: str}
    """
    response = client.messages.create(
        model=MODEL,
        max_tokens=256,
        messages=[{
            "role": "user",
            "content": (
                f"Inference derived from analogy: {inference}\n\n"
                f"Target domain: {target_problem}\n\n"
                "Is this inference valid in the target domain? "
                "List any constraints or counterexamples that limit its applicability. "
                "Respond as JSON: {{\"valid\": bool, \"caveat\": \"...\"}}"
            ),
        }],
    )
    raw = response.content[0].text.strip().lstrip("```json").lstrip("```").rstrip("```").strip()
    return json.loads(raw)
